const fresh=()=>({
 mode:'title',started:false,paused:false,player:{x:6*TILE,y:14*TILE,dir:'down',speed:142},trail:[],ninni:{x:5.5*TILE,y:14.5*TILE},camera:{x:0,y:0},
 team:[],reserve:[],seen:[],caught:[],quest:0,bossDefeated:false,endingType:null,dialogs:{tora:false,loke:false,siv:false,fjordGate:false},sideQuests:{loke:'available',siv:'available'},nightTrail:{stage:0,completed:false,rewarded:false},secrets:[],trial:{completed:false,active:false,wins:0,runs:0,bestBerries:null,berriesUsed:0},relics:[],inventory:{berries:2,wood:0,crystal:0,herb:0},
 base:{buildings:{workshop:0,training:0,garden:0},assignments:{workshop:null,training:null,garden:null},gardenCharge:0},gathered:[],trainers:{runa:0,aksel:0,inga:0,fjordMark:false},
 roamers:[],roamerSpawnAt:{forest:0,cave:0,fjord:0},scent:{activeUntil:0,cooldownUntil:0,target:null},particles:createAmbience(),
 moved:0,encounterCooldown:150,startTime:0,elapsed:0,best:Number(localStorage.getItem(BEST_KEY)||0),battle:null,message:'',sound:true,lastSave:0
});
