function draw(){ctx.clearRect(0,0,canvas.width,canvas.height);if(game.mode==='battle')drawBattle();else drawWorld();}
function update(dt){if(game.mode==='world'){const now=performance.now();updateRoamers(dt,now);let dx=(keys.has('ArrowRight')||keys.has('KeyD')?1:0)-(keys.has('ArrowLeft')||keys.has('KeyA')?1:0),dy=(keys.has('ArrowDown')||keys.has('KeyS')?1:0)-(keys.has('ArrowUp')||keys.has('KeyW')?1:0);if(dx&&dy){dx*=.707;dy*=.707;}tryMove(dx,dy,dt);game.camera.x=C.clamp(game.player.x-canvas.width/2,0,WORLD.w*TILE-canvas.width);game.camera.y=C.clamp(game.player.y-canvas.height/2,0,WORLD.h*TILE-canvas.height);if(now-game.lastSave>30000)saveGame();if(now-lastPanelUpdate>250){updatePanels();lastPanelUpdate=now;}}}
